    <text x="89" y="106" fill="#e4e4e7" font-size="12" text-anchor="middle">登録CASP</text>
    <text x="89" y="126" fill="#a1a1aa" font-size="12" text-anchor="middle">243→280社</text>

    <rect x="187" y="58" width="155" height="96" rx="10" fill="#241016" stroke="#ef4444" stroke-width="1.6"/>
    <text x="264" y="84" fill="#ef4444" font-size="13" font-weight="700" text-anchor="middle">7/8 CSA開始</text>
    <text x="264" y="106" fill="#e4e4e7" font-size="12" text-anchor="middle">ESMA発表</text>
    <text x="264" y="126" fill="#a1a1aa" font-size="12" text-anchor="middle">カストディ耐性</text>

    <rect x="362" y="58" width="155" height="96" rx="10" fill="#101c24" stroke="#38bdf8" stroke-width="1.6"/>
    <text x="439" y="84" fill="#38bdf8" font-size="13" font-weight="700" text-anchor="middle">'26下~'27上</text>
